function JsonInspector() {
  const [input, setInput] = React.useState('{\n  "users": [\n    { "id": 1, "name": "Alice", "active": true },\n    { "id": 2, "name": "Bob", "active": false }\n  ],\n  "count": 2,\n  "meta": { "version": "1.0" }\n}');
  const [error, setError] = React.useState(null);

  let parsed = null;
  try {
    parsed = JSON.parse(input);
  } catch (e) {
    // leave parsed as null
  }

  React.useEffect(() => {
    try {
      JSON.parse(input);
      setError(null);
    } catch (e) {
      setError(e.message);
    }
  }, [input]);

  function formatJson() {
    try {
      const obj = JSON.parse(input);
      setInput(JSON.stringify(obj, null, 2));
      setError(null);
    } catch (e) {
      setError(e.message);
    }
  }

  function minifyJson() {
    try {
      const obj = JSON.parse(input);
      setInput(JSON.stringify(obj));
      setError(null);
    } catch (e) {
      setError(e.message);
    }
  }

  function TreeNode({ label, value, depth }) {
    const [expanded, setExpanded] = React.useState(true);
    const indent = depth * 16;
    const type = Array.isArray(value) ? 'array' : typeof value === 'object' && value !== null ? 'object' : 'primitive';
    const isExpandable = type === 'object' || type === 'array';
    const keys = isExpandable ? Object.keys(value) : [];
    const count = keys.length;

    if (type === 'primitive') {
      let color = '#1a1a1a';
      if (typeof value === 'string') color = '#16a34a';
      if (typeof value === 'number') color = '#2563eb';
      if (typeof value === 'boolean') color = '#d97706';
      if (value === null) color = '#9ca3af';
      return (
        <div style={{ paddingLeft: indent, fontSize: 13, fontFamily: 'monospace', lineHeight: '20px' }}>
          <span style={{ color: '#6b7280' }}>{label ? label + ': ' : ''}</span>
          <span style={{ color }}>{typeof value === 'string' ? '"' + value + '"' : String(value)}</span>
        </div>
      );
    }

    return (
      <div>
        <div
          style={{ paddingLeft: indent, fontSize: 13, fontFamily: 'monospace', lineHeight: '20px', cursor: isExpandable ? 'pointer' : 'default', userSelect: 'none' }}
          onClick={() => isExpandable && setExpanded(!expanded)}
        >
          <span style={{ color: '#6b7280', marginRight: 4 }}>{expanded ? '\u25bc' : '\u25b6'}</span>
          <span style={{ color: '#6b7280' }}>{label ? label + ': ' : ''}</span>
          <span style={{ color: '#6b7280' }}>{type === 'array' ? '[' + count + ']' : '{' + count + '}'}</span>
        </div>
        {expanded && keys.map((k, i) => (
          <TreeNode key={i} label={type === 'array' ? i : k} value={value[k]} depth={depth + 1} />
        ))}
      </div>
    );
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>JSON Inspector</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <button onClick={formatJson} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Format</button>
        <button onClick={minifyJson} style={{ padding: '6px 14px', borderRadius: 6, border: '1px solid #ddd', background: '#fff', fontSize: 13, cursor: 'pointer' }}>Minify</button>
      </div>
      <textarea
        value={input}
        onChange={e => setInput(e.target.value)}
        style={{ width: '100%', height: 100, padding: 10, borderRadius: 6, border: error ? '1px solid #ef4444' : '1px solid #ddd', fontSize: 12, fontFamily: 'monospace', resize: 'none', boxSizing: 'border-box', marginBottom: 12 }}
        placeholder="Paste JSON here..."
      />
      {error && <div style={{ color: '#ef4444', fontSize: 12, marginBottom: 8 }}>{error}</div>}
      <div style={{ flex: 1, overflow: 'auto', border: '1px solid #e5e7eb', borderRadius: 6, padding: 10, background: '#f9fafb' }}>
        {parsed !== null ? <TreeNode value={parsed} depth={0} /> : <div style={{ color: '#999', fontSize: 13 }}>Invalid JSON</div>}
      </div>
    </div>
  );
}
render(<JsonInspector/>);
